item.params:
select case count(a.id) when 0 then 'good' else concat(count(a.id)::text,': ',string_agg(a.id::text, ',')) end as ca from "Account" a, "AccountClientAction" aca, "ClientAction" ca
where aca.account_id = a.id and aca.clientaction_id = ca.id and a.status = 1 and accounttype = 0
and aca.deleted = false and aca.iterationsleft = -1 and ca.friendlyname ilike '%10 day%';

select case count(a.id) when 0 then 'good' else concat(count(a.id)::text,': ',string_agg(a.id::text, ',')) end as ca from "Account" a, "AccountClientAction" aca, "ClientAction" ca
where aca.account_id = a.id and aca.clientaction_id = ca.id and a.status = 1 and accounttype = 0
and aca.deleted = false and aca.iterationsleft = -1 and ca.friendlyname ilike '%10 day%';

select case count(m.sap) when 0 then 'good' else count(m.sap)::text || ': ' || string_agg(coalesce(ea.id::text,'null') || ', ' || m.sap, '; ') || ';' end as ca
from dblink('dbname=microchipregistration port=5432 host=microchipregistrationservice.db.actdata.io user=zabbix password=2hw\|ED\,p\`p\]Axcx\?a',
'select accountid,substring(connectionstring ,'';(\d*);'') a_id from "StateInstance" where active = true and pulltype = 1') as m (sap varchar(255),account_id bigint)
left join "EnterpriseAccount" ea on ea.account_id = m.account_id and ea.enterprisecustomer_id = 11
/*,left join lateral (select * from "AccountStatusChange" where enterpriseaccount_id = ea.id order by changed desc limit 1) sc*/
where ea.status is distinct from 1;

select case when max(vsurvimportdate)::date < now()::date
then to_char(max(vsurvimportdate)::timestamp at time zone 'utc' at time zone 'CST6CDT', 'Day FMMM/FMDD FMHH:MI AM') else 'good' end as lastvsurvimportdate
from "InvoiceItem";

select coalesce(string_agg(aca.id::varchar,','), 'good') from "AccountClientAction" aca
left join "ActionSuccess" acs on aca.clientaction_id = acs.clientaction_id and aca.account_id = acs.account_id and logged > now() - interval '3 day'
where acs.id is null and settingsjson LIKE '%"useApiIds":"true"%';
